registerModule('Movement Trail', function(g) {
  g._trail = g._trail || { points: [], maxLen: 60 };

  var trail = g._trail;
  var ctx = g.ctx;
  var moving = g.vx !== 0 || g.vy !== 0;

  if (moving) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
  }

  // Age all points and remove expired ones
  var alive = [];
  for (var i = 0; i < trail.points.length; i++) {
    trail.points[i].age++;
    if (trail.points[i].age < trail.maxLen) {
      alive.push(trail.points[i]);
    }
  }
  trail.points = alive;

  // Draw trail segments
  for (var j = 0; j < trail.points.length; j++) {
    var pt = trail.points[j];
    var t = 1 - (pt.age / trail.maxLen);
    var size = t * 4;

    // Color shifts from cyan-green to purple as it fades
    var r = Math.floor(g.lerp(80, 0, t));
    var gb = Math.floor(g.lerp(80, 255, t));
    var b = Math.floor(g.lerp(160, 170, t));
    var alpha = t * 0.85;

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.shadowBlur = size * 3;
    ctx.shadowColor = 'rgba(' + r + ',' + gb + ',' + b + ',1)';
    ctx.fillStyle = 'rgba(' + r + ',' + gb + ',' + b + ',1)';
    ctx.fillRect(
      Math.round(pt.x - size / 2),
      Math.round(pt.y - size / 2),
      Math.max(1, Math.round(size)),
      Math.max(1, Math.round(size))
    );
    ctx.restore();
  }
})

registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    var W = g.canvas.width, H = g.canvas.height;
    for (var i = 0; i < 180; i++) {
      arr.push({
        x: Math.random() * W,
        y: Math.random() * H,
        z: Math.random(),
        size: 0,
        speed: 0,
        brightness: 0,
        twinkle: Math.random() * Math.PI * 2,
        twinkleSpeed: 0.01 + Math.random() * 0.04,
        color: 0
      });
    }
    return arr;
  })();

  g._starsPalette = g._starsPalette || [
    [180, 200, 255],
    [255, 255, 255],
    [255, 220, 180],
    [180, 255, 220],
    [220, 180, 255]
  ];

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = g._stars;
  var palette = g._starsPalette;

  // Drift stars slowly opposite to player velocity for parallax
  var driftX = -g.vx * 0.18;
  var driftY = -g.vy * 0.18;

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Lazy init / recalc size+speed from z
    s.size = 0.4 + s.z * 1.8;
    s.speed = 0.08 + s.z * 0.35;
    s.color = Math.floor(s.z * (palette.length - 1) + 0.5);

    // Move with parallax
    s.x += driftX * s.speed + (s.z * 0.12);
    s.y += driftY * s.speed + (s.z * 0.04);

    // Wrap around canvas edges
    if (s.x < -2) s.x = W + 2;
    if (s.x > W + 2) s.x = -2;
    if (s.y < -2) s.y = H + 2;
    if (s.y > H + 2) s.y = -2;

    // Twinkle
    s.twinkle += s.twinkleSpeed;
    s.brightness = 0.45 + 0.55 * (0.5 + 0.5 * Math.sin(s.twinkle));

    // Draw
    var col = palette[s.color < 0 ? 0 : s.color >= palette.length ? palette.length - 1 : s.color];
    var r = col[0], gr = col[1], b = col[2];
    var alpha = s.brightness * (0.3 + s.z * 0.7);

    if (s.size > 1.2) {
      // Larger stars: soft glow
      var grd = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.size * 2.5);
      grd.addColorStop(0, 'rgba(' + r + ',' + gr + ',' + b + ',' + alpha + ')');
      grd.addColorStop(1, 'rgba(' + r + ',' + gr + ',' + b + ',0)');
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.size * 2.5, 0, Math.PI * 2);
      ctx.fillStyle = grd;
      ctx.fill();
    }

    // Core dot
    ctx.beginPath();
    ctx.arc(s.x, s.y, s.size * 0.7, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(' + r + ',' + gr + ',' + b + ',' + (alpha * 1.0) + ')';
    ctx.fill();
  }
})

registerModule("Floating Particle Spawner", function(g) {
  var ctx = g.ctx;
  var w = g.canvas.width;
  var h = g.canvas.height;

  // Spawn particles periodically near player
  if (g.tick % 25 === 0 && g.particles.length < 50) {
    var angle = Math.random() * Math.PI * 2;
    var dist = 100 + Math.random() * 250;
    var px = g.px + Math.cos(angle) * dist;
    var py = g.py + Math.sin(angle) * dist;

    // Wrap to screen
    px = ((px % w) + w) % w;
    py = ((py % h) + h) % h;

    g.particles.push({
      x: px, y: py,
      size: 2 + Math.random() * 3,
      color: Math.random() > 0.5 ? "#00ffaa" : "#7c3aed",
      pulse: Math.random() * Math.PI * 2,
      life: 1
    });
  }

  // Update, draw, and check absorption
  for (var i = g.particles.length - 1; i >= 0; i--) {
    var p = g.particles[i];
    p.pulse += 0.05;

    // Gentle float
    p.y += Math.sin(p.pulse) * 0.3;
    p.x += Math.cos(p.pulse * 0.7) * 0.2;

    // Wrap particles
    if (p.x < 0) p.x = w;
    if (p.x > w) p.x = 0;
    if (p.y < 0) p.y = h;
    if (p.y > h) p.y = 0;

    // Check absorption — player touches particle
    var dx = p.x - g.px;
    var dy = p.y - g.py;
    var d = Math.sqrt(dx * dx + dy * dy);

    if (d < 14) {
      g.score += 10;
      g.absorbed++;
      g.particles.splice(i, 1);
      continue;
    }

    // Draw particle with pulsing glow
    var s = p.size * (0.8 + Math.sin(p.pulse) * 0.2);
    ctx.globalAlpha = 0.6 + Math.sin(p.pulse) * 0.3;
    ctx.fillStyle = p.color;
    ctx.shadowColor = p.color;
    ctx.shadowBlur = 6;
    ctx.beginPath();
    ctx.arc(p.x, p.y, Math.max(0.5, s), 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowBlur = 0;
    ctx.globalAlpha = 1;
  }
});
